\vspace{2mm}
\begin{itemize}
    \item Šikmé úseky -- látka mění teplotu (ohřev / chlazení).
    \item Vodorovné úseky -- látka mění \textbf{skupenství}, teplota se nemění.
\end{itemize}

\vspace{4mm}
{\Large \bfseries \color{zfblue} Skupenská tepla různých látek}
\vspace{2mm}

\begin{center}
